// Extract latitude and longitude from location message
const message = $json.body?.message || {};
const location = message.location;

if (!location || !location.latitude || !location.longitude) {
  return [{ json: {
    locationError: true,
    errorMsg: 'No location data received.',
    telegramId: $('Get User Profile').item.json.telegram_id
  } }];
}

return [{ json: {
  locationError: false,
  lat: location.latitude,
  lon: location.longitude,
  userId: $('Get User Profile').item.json.id,
  telegramId: $('Get User Profile').item.json.telegram_id,
  goal: $('Get User Profile').item.json.goal,
  firstName: $('Get User Profile').item.json.first_name
} }];

// Filter and format restaurant results
const placesData = $json;
const locData = $('Extract Location').item.json;

const results = (placesData.results || []);
const filtered = results
  .filter(r => r.rating >= 4.0 && r.business_status === 'OPERATIONAL')
  .slice(0, 5);

if (filtered.length === 0) {
  return [{ json: {
    noResults: true,
    telegramId: locData.telegramId,
    lat: locData.lat,
    lon: locData.lon
  } }];
}

const formatted = filtered.map(r => ({
  name: r.name,
  rating: r.rating,
  address: r.vicinity,
  placeId: r.place_id,
  priceLevel: r.price_level,
  openNow: r.opening_hours?.open_now
}));

return [{ json: {
  noResults: false,
  restaurants: formatted,
  count: formatted.length,
  telegramId: locData.telegramId,
  userId: locData.userId,
  goal: locData.goal,
  firstName: locData.firstName,
  lat: locData.lat,
  lon: locData.lon
} }];

