// Combine restaurant data with AI explanations
const restaurants = $('Filter & Format Results').item.json.restaurants;
const explanationsText = $json.message?.content || $json.choices?.[0]?.message?.content || '';
const prevData = $('Filter & Format Results').item.json;

// Parse explanations by line number
const explanationLines = explanationsText.split('\n').filter(l => l.trim());
const explanations = {};
explanationLines.forEach(line => {
  const match = line.match(/^(\d+)[\.:\)]\s*(.+)/);
  if (match) {
    explanations[parseInt(match[1]) - 1] = match[2].trim();
  }
});

const priceMap = { 1: '$', 2: '$$', 3: '$$$', 4: '$$$$' };

const messages = restaurants.map((r, i) => {
  const openStatus = r.openNow === true ? '🟢 Open now' : r.openNow === false ? '🔴 Closed' : '';
  const price = priceMap[r.priceLevel] || '';
  const explanation = explanations[i] || 'A solid option for healthy eating.';

  return `🍴 <b>${r.name}</b>\n` +
    `⭐ ${r.rating} ${price} ${openStatus}\n` +
    `📍 ${r.address}\n` +
    `💡 ${explanation}`;
});

return [{ json: {
  messageChunks: messages,
  telegramId: prevData.telegramId,
  userId: prevData.userId,
  count: restaurants.length,
  lat: prevData.lat,
  lon: prevData.lon
} }];

